// Helper functions
export function getProductByHandle(handle) {
    return products.find(p => p.handle === handle) || null;
}

export function getProductsByPillar(pillar) {
    if (!pillar || pillar === "All") return products;
    return products.filter(p => p.pillar === pillar);
}

export function searchProducts(query) {
    const q = query.toLowerCase();
    return products.filter(p =>
        p.name.toLowerCase().includes(q) ||
        p.brand.toLowerCase().includes(q) ||
        p.pillar.toLowerCase().includes(q) ||
        p.category.toLowerCase().includes(q) ||
        p.keyIngredients.toLowerCase().includes(q)
    );
}

export function getFeaturedProducts() {
    // Hand-picked hero products for homepage
    const featured = ["calm-tea", "ease-oil-non-rx", "recover-spray-non-rx", "relax-roll-on-non-rx", "digest-capsules-non-rx", "lion-s-mane-fruiting-body-extract-powder"];
    return featured.map(h => getProductByHandle(h)).filter(Boolean);
}